        ("Kerosene",          "71.9 t/TJ",    "IPCC 2019 Guidelines"),
        ("Firewood",          "112.0 t/TJ",   "IPCC 2019 Guidelines"),
        ("Coal / Charcoal",   "112.0 t/TJ",   "IPCC 2019 Guidelines"),
